{
    "coupon": "my-coupon-id",				// required, alphanumeric coupon ID
    "discount": {							
    	"type": "flat", 					// required, Valid values for type are flat and percent. Flat expects object with amount off per currency.
    	"amount": {
    		"USD": 8,	
    		"EUR": 1
    	}
    },
    "combine": true,						// optional, Corresponds to "combine discounts" in the interface. Default: false. If enabled will apply coupon discount in addition to the product discount.
    "reason": {								// optional, Discount reason visible to end users, object with all languages you want to enter it in.
    	"en": "Your Reason", 
    	"de": "Your Reason in German"
    },
    "limit": 10,							// optional, Usage limit for each coupon code
    "available": {							// optional, Accepts timestamp in milliseconds and datetime string  e.g. "2015-09-01 08:00" to set "start time" or "end time"
    	"start":"2019-12-01", 
    	"end": "2019-12-31"
    },
    "codes": [								//optional, Array of coupon codes which trigger this discount
    	"code1", 
    	"code2", 
    	"code3"
    ], 
    "products": [							// optional, Array of product ids to which this discount applies. If not provided applies to all products.
    	"base"
    ] 
}

