{ 
   "account":"{account_id}",			              // must have billing method on file
   "coupon":"",                         	         // optional couponID
   "tags":{ 										// optional tags
      "tag1":"value1"
   },
   "currency":"USD",
   "items":[ 
      { 
         "product":"{product_id}",  				// productID
         "quantity":1,
         "pricing":{ 
            "trial":0,                              // days
            "renew":"auto",                         // or "manual", "opt-auto", "opt-manual"
            "interval":"month",                     // or "adhoc", "day", "week", "year"
            "intervalLength":1,                     // required if "intervral" is specified and is not "adhoc"
            "quantityBehavior":"allow",             // or "lock" or "hide"
            "quantityDefault":1,
            "price":{ 
               "USD":14.95,                         // currency must be enabled in the Store Settings
               "EUR":10.99
            }
         },
         "attributes":{ 
            "ATTRIBUTE1":"value1"                   // optional custom product-level attributes
         }
      }
   ]
}

{
  "orders": [
    {
      "order": "{order_id}",                                // order ID to be updated
      "tags": {
        "TagKey1": "TagValue1",                                         // order tag to be added or updated
        "TagKey2": "TagValue2"                                          // order tag to be added or updated
      },
      "items": [
        {
          "product": "product_id}",                                // product path of the product whose attributes will be added or updated
          "attributes": {
            "AttributeKey1": "AttributeValue1",                         // attribute to be added or updated
            "AttributeKey2": "AttributeValue2"                          // attribute to be added or updated
          }
        }
      ]
    }
  ]
}

{
  "products": [
    {
      "product": "{product_path}",                                                 // Required. Must be a valid product path/ID: alphanumeric, all lower-case, no special characters except dash "-", must be greater than two characters in length
      "display": {                                                              // Required at least in English
        "en": "String"                                                          
      },
      "description": {
        "summary": {
          "en": "String"                                                        // This field also supports Markdown.
        },
        "action": {
          "en": "String"                                                        
        },
        "full": {
          "en": "String"                                                        // This field also supports Markdown.
        }
      },
      "fulfillment": {
        "instructions":{                                                        // Optional Post Order Instructions (e.g. for a 'thank you message' and directions on how to register the product)
          "en":"String",                                                        // This field also supports Markdown.
          "es":"String"                                                         // This field also supports Markdown.
        } 
      }, 
      "image": "https://d8y8nchqlnmka.cloudfront.net/NVaGM-nhSpQ/-FooqIP-R84/photio-imac-hero.png",             // Product icon image
      "format": "digital",                                                      // Or "physical" or "digital-and-physical"
      "sku": "string",                                                          // Optional SKU ID string
      "attributes": {                                                           // Strings. Custom key / value attributes that will be passed back once this product is purchased 
        "key1": "value1",
        "key2": "value2"
      }, 
      "pricing": {
        "trial": 2,                                                             // Days, only needed if you are creating a subscription
        "interval": "month",                                                    // Or "adhoc", "day", "week", "year", only needed if you are creating a subscription
        "intervalLength": 1,                                                    // Required if "interval" is specified and is not "adhoc"
        "quantityBehavior": "allow",                                            // Or "lock" or "hide"
        "quantityDefault": 1,
        "price": {
          "USD": 14.95,                                                         // Currency must be enabled in the Store Settings
          "EUR": 10.99
        },
        "quantityDiscounts": {                                                  // "Volume Discounts". Support perentage or "amount off". Mixed values are not supported. 
          10: 25.00                                                            // Quantity: percentage off. Everything more than 10 units will be discounted by 25%.
        },
        "discountReason": {
          "en": "The Reason"
        },
        "discountDuration": 1
      }
    }
  ]
}

